frappe.ui.form.on('Onboarding Schedule', {
    refresh(frm) {
        if (!frm.is_new()) {

            // SINGLE WELCOME EMAIL BUTTON
            if (!frm.doc.send_welcome_email) {
                frm.add_custom_button(__('Send Employee Welcome'), function () {
                    open_email_dialog(frm, "single");
                }, __('Email Actions'));
            }

            // GLOBAL COMPANY-WIDE EMAIL BUTTON
            if (!frm.doc.send_company_wide_email_intro) {
                frm.add_custom_button(__('Send Global Email Invite'), function () {
                    open_email_dialog(frm, "global");
                }, __('Email Actions'));
            }

            // 30-DAY SURVEY BUTTON - show only if employee is linked and survey not yet sent
            if (frm.doc.employee && !frm.doc['30_day_feedback_survey']) {
                frm.add_custom_button(__('Send 30-Day Survey'), function () {
                    frappe.confirm(
                        __('Send the 30-day onboarding feedback survey to <b>{0}</b>?',
                            [frm.doc.employee_name || frm.doc.employee]),
                        function () {
                            frappe.call({
                                method: 'corporate_services.api.notification.onboarding.onboarding_schedule.send_30day_feedback_survey',
                                args: {
                                    employee_name: frm.doc.employee,
                                    docname: frm.doc.name
                                },
                                freeze: true,
                                freeze_message: __('Sending 30-day survey...'),
                                callback: function (r) {
                                    if (!r.exc) {
                                        frappe.msgprint({
                                            title: __('Survey Sent'),
                                            message: __(r.message),
                                            indicator: 'green'
                                        });
                                        frm.reload_doc();
                                    }
                                }
                            });
                        }
                    );
                }, __('Email Actions'));
            }
        }
    }
});

function open_email_dialog(frm, mode) {
    let d = new frappe.ui.Dialog({
        title: mode === "single" ? 'Send Welcome Email' : 'Send Global Email Invite',
        fields: [
            {
                label: 'Email Template',
                fieldname: 'email_template',
                fieldtype: 'Link',
                options: 'Email Template',
                reqd: 1
            },
            {
                label: 'Additional Information',
                fieldname: 'custom_message',
                fieldtype: 'Small Text',
                reqd: 1
            }
        ],
        primary_action_label: 'Send Email',
        primary_action(values) {
            frappe.call({
                method: mode === "single"
                    ? 'corporate_services.api.notification.onboarding.onboarding_schedule.send_welcome_email'
                    : 'corporate_services.api.notification.onboarding.onboarding_schedule.send_global_email_invite',
                args: {
                    docname: frm.doc.name,
                    email_template: values.email_template,
                    custom_message: values.custom_message
                },
                freeze: true,
                freeze_message: __('Sending emails...'),
                callback: function (r) {
                    if (!r.exc) {
                        frappe.msgprint(__('Email(s) sent successfully.'));
                        d.hide();
                        frm.reload_doc();
                    }
                }
            });
        }
    });
    d.show();
}

