frappe.ui.form.on('Timesheet Submission', {
    refresh: function(frm) {
        if (!frm.doc.__islocal && !frm.doc.timesheet_imported) {
            frm.add_custom_button(__('Import Timesheet'), function() {
                if (frm.doc.timesheet) {
                    frappe.call({
                        method: 'corporate_services.api.timesheet.timesheet_import.timesheet_import',
                        args: {
                            docname: frm.doc.name
                        },
                        callback: function(response) {
                            if (response.message && response.message.status === 'success') {
                                frappe.msgprint({
                                    title: __('Timesheet Imported'),
                                    message: __('Timesheet imported successfully. Total working hours: <b>') + response.message.total_hours + __('</b>.<br><br>Please go ahead and submit to your supervisor for review.'),
                                    indicator: 'green'
                                });
                                frm.set_value('timesheet_imported', 1);
                                fetch_timesheets_for_employee(frm);
                                frm.save();
                            } else {
                                frappe.msgprint(__('There was an error creating the employee timesheet.'));
                            }
                        }
                    });
                } else {
                    frappe.msgprint(__('Please upload a timesheet file before importing.'));
                }
            });
        }

        // Override the default delete button behavior completely
        if (!frm.doc.__islocal) {
            setTimeout(function() {
                let delete_btn = frm.page.menu.find('.dropdown-item:contains("Delete")');
                if (delete_btn.length > 0) {
                    delete_btn.off('click').on('click', function(e) {
                        e.preventDefault();
                        e.stopPropagation();
                        e.stopImmediatePropagation();
                        delete_with_confirmation(frm);
                        return false;
                    });
                }
            }, 100);
        }
    },
    timesheet: function(frm) {
        if (frm.doc.timesheet_imported) {
            frm.set_value('timesheet_imported', 0);
        }
    }
});

function fetch_timesheets_for_employee(frm) {
    frappe.call({
        method: 'corporate_services.api.timesheet.timesheet_fetch.fetch_timesheets_for_employee',
        args: {
            employee_id: frm.doc.employee,
            month: frm.doc.month_year,
            docname: frm.doc.name
        },
        callback: function(r) {
            if (!r.exc) {
                frm.clear_table('timesheet_per_project');
                if (r.message && r.message.timesheets && r.message.timesheets.length > 0) {
                    r.message.timesheets.forEach(function(timesheet) {
                        let child = frm.add_child('timesheet_per_project');
                        child.timesheet = timesheet.name;
                        child.total_hours = timesheet.total_hours;
                        child.project = timesheet.parent_project;
                        child.month = timesheet.custom_month;
                        child.percent = timesheet.percent_pay;
                        child.pay = timesheet.pay_for_project;
                        child.timesheet_type = timesheet.custom_timesheet_type;
                        child.status = timesheet.status;
                    });
                    frm.refresh_field('timesheet_per_project');

                    frm.set_value('total_working_hours', r.message.total_working_hours);
                } else {
                    frappe.msgprint(__('No timesheets found for the employee.'));
                }
            } else {
                frappe.msgprint(__('There was an error fetching timesheets.'));
            }
        }
    });
}

function delete_with_confirmation(frm) {
    frappe.call({
        method: 'frappe.client.get_count',
        args: {
            doctype: 'Timesheet Submission List',
            filters: {
                'parent': frm.doc.name
            }
        },
        callback: function(r) {
            let linked_count = r.message || 0;

            let message = '';
            if (linked_count > 0) {
                message = __('This will permanently delete:') + '\n\n' +
                         __('• Timesheet Submission: {0}', [frm.doc.name]) + '\n' +
                         __('• {0} linked Timesheet(s)', [linked_count]) + '\n\n' +
                         __('This action cannot be undone!') + '\n\n' +
                         __('Are you sure you want to continue?');
            } else {
                message = __('Are you sure you want to delete Timesheet Submission {0}?', [frm.doc.name]);
            }

            frappe.confirm(
                message,
                function() {
                    frappe.show_alert({
                        message: __('Deleting...'),
                        indicator: 'orange'
                    });

                    if (linked_count > 0) {
                        frappe.call({
                            method: 'corporate_services.api.timesheet.overrides.timesheet_submission.delete_timesheet_submission_with_linked',
                            args: {
                                'timesheet_submission_name': frm.doc.name
                            },
                            freeze: true,
                            freeze_message: __('Deleting Timesheet Submission and linked records...'),
                            callback: function(r) {
                                if (r.message) {
                                    if (r.message.success) {
                                        frappe.show_alert({
                                            message: r.message.message,
                                            indicator: 'green'
                                        });

                                        // Redirect to list view
                                        setTimeout(function() {
                                            frappe.set_route('List', 'Timesheet Submission');
                                        }, 1500);
                                    } else {
                                        frappe.show_alert({
                                            message: __('Error: {0}', [r.message.message]),
                                            indicator: 'red'
                                        });
                                    }
                                } else {
                                    frappe.show_alert({
                                        message: __('Unexpected response format'),
                                        indicator: 'red'
                                    });
                                }
                            },
                            error: function(r) {
                                let error_message = __('Error occurred while deleting');
                                if (r.responseJSON && r.responseJSON.message) {
                                    error_message = r.responseJSON.message;
                                }
                                frappe.show_alert({
                                    message: error_message,
                                    indicator: 'red'
                                });
                            }
                        });
                    } else {
                        frappe.call({
                            method: 'frappe.client.delete',
                            args: {
                                doctype: 'Timesheet Submission',
                                name: frm.doc.name
                            },
                            freeze: true,
                            freeze_message: __('Deleting Timesheet Submission...'),
                            callback: function(r) {
                                frappe.show_alert({
                                    message: __('Timesheet Submission deleted successfully'),
                                    indicator: 'green'
                                });

                                setTimeout(function() {
                                    frappe.set_route('List', 'Timesheet Submission');
                                }, 1000);
                            },
                            error: function(r) {
                                frappe.show_alert({
                                    message: __('Error deleting Timesheet Submission'),
                                    indicator: 'red'
                                });
                            }
                        });
                    }
                },
                function() {
                    frappe.show_alert({
                        message: __('Delete operation cancelled'),
                        indicator: 'blue'
                    });
                }
            );
        },
        error: function(r) {
            frappe.show_alert({
                message: __('Error getting linked timesheet count'),
                indicator: 'red'
            });
        }
    });
}

frappe.ui.form.on('Timesheet Submission', {
    refresh: function(frm) {
        frm.fields_dict.download_template.$input.on('click', function() {
            frappe.call({
                method: "corporate_services.api.timesheet.timesheet_generation_export.timesheet_generation_export",
                args: {
                    docname: frm.doc.name
                },
                callback: function(r) {
                    if (r.message && typeof r.message === 'string' && r.message !== "error") {
                        var download_url = r.message;
                        window.open(download_url, '_blank');

                    } else if (r.message && typeof r.message === 'object') {
                        var download_url = r.message.file_url;
                        window.open(download_url, '_blank');

                    } else {
                        frappe.msgprint(__("Failed to generate CSV file. Please check logs for details."));
                    }
                }
            });
        });
    }
});

