frappe.ui.form.on('Employee Grievance', {
    refresh: function(frm) {
        function toggle_fields() {
            const isHRManager = frappe.user.has_role('HR Manager');
            frm.toggle_display('cause_of_grievance', isHRManager);
            frm.toggle_display('resolution_detail', isHRManager);
        }

        toggle_fields();

        frm.fields_dict.workflow_state.$input.on('change', function() {
            toggle_fields();
        });
    },
    before_save: function(frm) {
        if (!frappe.user.has_role('HR Manager')) {
            frm.toggle_display('cause_of_grievance', false);
            frm.toggle_display('resolution_detail', false);
        }
    }
});

frappe.ui.form.on('Leave Application', {
    from_date: function(frm) {
        // Check if the leave type is Annual Leave
        if (frm.doc.leave_type === 'Annual Leave') {
            // Check if the user is not an HR Manager
            if (!frappe.user_roles.includes('HR Manager')) {
                const noticePeriod = frm.doc.annual_leave_notice_period || 7;
                const minDate = frappe.datetime.add_days(frappe.datetime.get_today(), noticePeriod);
                if (frm.doc.from_date < minDate) {
                    frappe.msgprint("You must apply for Annual Leave at least " + noticePeriod + " days in advance.");
                    frm.set_value('from_date', '');
                    frappe.validated = false;
                }
            }
        }
    }
});

