function get_currency_symbol(frm) {
    if (frm.doc.currency) {
        let currency_doc = frappe.model.get_doc('Currency', frm.doc.currency);
        return currency_doc ? currency_doc.symbol : '';
    }
    return '';
}

function calculate_totals(frm) {
    let total_spent = 0;
    let total_amount_local = 0;

    if (frm.doc.activity_participants_reconciliation) {
        frm.doc.activity_participants_reconciliation.forEach(row => {
            total_spent += parseFloat(row.total_paid) || 0;
            total_amount_local += parseFloat(row.amount_in_local_currency) || 0;
        });
    }

    let currency_symbol = get_currency_symbol(frm);

    // Set values directly instead of using async set_value
    frm.set_value('total_spent', currency_symbol + ' ' + format_number(total_spent));
    frm.set_value('total_local_amount', format_number(total_amount_local));

    let total_advance = 0;
    if (frm.doc.currency === 'KES') {
        total_advance = parseFloat(frm.doc.local_total_advance) || 0;
    } else {
        total_advance = get_number_value(frm.doc.total_advance);
    }

    frm.set_value('total_advance', currency_symbol + ' ' + format_number(total_advance));

    let total_spent_value = get_number_value(frm.doc.total_spent);
    let balance = total_advance - total_spent_value;

    frm.set_value('total_balance', currency_symbol + ' ' + format_number(balance));
}

function format_number(value) {
    if (!value) value = 0;
    return parseFloat(value).toLocaleString('en-US', { 
        minimumFractionDigits: 2, 
        maximumFractionDigits: 2 
    });
}

function get_number_value(value) {
    if (!value) return 0;
    return parseFloat(value.toString().replace(/[^\d.-]/g, "")) || 0;
}

