frappe.ui.form.on('Timesheet Submission', {
    before_workflow_action: function(frm) {
        // Store the pending workflow action
        if (!frm.confirmed_workflow_action) {
            // Get the action that's being attempted
            const action = frm.selected_workflow_action;

            // Show confirmation dialog
            frappe.confirm(
                `Aree you sure you want to perform this action: <strong>${action}</strong>?`,
                () => {
                    // If confirmed, set flag and trigger the action
                    frm.confirmed_workflow_action = true;
                    frm.selected_workflow_action = action;
                    frm.workflow_action(action);
                },
                () => {
                    // If cancelled, show message
                    frappe.msgprint("Action cancelled.");
                }
            );

            // Prevent default workflow action until confirmed
            return false;
        } else {
            // Reset the confirmation flag for next time
            frm.confirmed_workflow_action = false;
            // Allow the workflow action to proceed
            return true;
        }
    }
});

