                method: 'frappe.client.get',
                args: {
                    doctype: 'Employee',
                    name: frm.doc.custom_allocate_to
                },
                callback: function(r) {
                    if (r.message) {
                        const employee = r.message;
                        const email = employee.company_email || employee.personal_email;
                        if (email) {
                            frappe.show_alert({
                                message: __('Email will be sent to: {0} ({1})', [employee.employee_name, email]),
                                indicator: 'green'
                            });
                        } else {
                            frappe.msgprint({
                                title: __('No Email Address'),
                                message: __('Selected employee does not have an email address. Please update employee record.'),
                                indicator: 'red'
                            });
                        }
                    }
                }
            });
        }
    },

    before_save: function(frm) {
        // Validate before saving
        if (frm.doc.custom_send_email && !frm.doc.custom_allocate_to) {
            frappe.msgprint({
                title: __('Missing Information'),
                message: __('Please select an employee in "Allocate To" field to send email notification.'),
                indicator: 'red'
            });
            frappe.validated = false;
            return false;
        }
    }
});

