const PERFORMANCE_AREAS = [
    { performance_area: 'Job Knowledge and Skills', criteria: ['Competency in job-specific knowledge and skills.', 'Ability to apply knowledge effectively in tasks and projects.'] },
    { performance_area: 'Quality of Work', criteria: ['Consistency and accuracy in delivering high-quality work.', 'Attention to detail and adherence to standards.'] },
    { performance_area: 'Communication', criteria: ['Effectiveness in verbal and written communication.', 'Ability to collaborate and share information with team members.'] },
    { performance_area: 'Teamwork', criteria: ['Contribution to team goals and initiatives.', 'Ability to work collaboratively with colleagues.'] },
    { performance_area: 'Problem-Solving and Decision-Making', criteria: ['Aptitude for identifying and resolving challenges.', 'Ability to make sound decisions based on available information.'] },
    { performance_area: 'Innovation', criteria: ['Willingness to suggest and implement innovative ideas.'] },
    { performance_area: 'Leadership and Management Skills', criteria: ['Ability to lead and manage teams effectively.', 'Demonstrated leadership qualities such as motivation, delegation, and decision-making.'] },
    { performance_area: 'Adaptability and Flexibility', criteria: ['Capacity to adapt to changing work environments, tasks, or priorities.', 'Willingness to embrace new challenges and learn new skills.'] },
    { performance_area: 'Time Management and Organization', criteria: ['Ability to prioritize tasks and manage time effectively.', 'Demonstrated organizational skills in handling workload and meeting deadlines.'] },
    { performance_area: 'Initiative and Proactivity', criteria: ['Proactiveness in taking on new responsibilities.', 'Willingness to take initiative and responsibility for tasks or projects.', 'Demonstrated proactivity in seeking out opportunities for improvement or advancement.'] },
    { performance_area: 'Ethical Conduct and Integrity', criteria: ['Commitment to ethical behavior and adherence to company policies and values.', 'Demonstrated integrity in handling confidential information and maintaining professional standards.'] }
];

const RATING_OPTIONS = ['No Rating', 'Unsatisfactory', 'Requires Improvement', 'Satisfactory', 'Meets Expectations', 'Outstanding'];

const RATING_SCORES = {
    'No Rating': 0, 'Unsatisfactory': 1, 'Requires Improvement': 2,
    'Satisfactory': 3, 'Meets Expectations': 4, 'Outstanding': 5
};

frappe.ui.form.on('Performance Appraisal', {
    onload: function(frm) {
        frm.set_df_property('current_performance', 'hidden', 1);
    },

    refresh: function(frm) {
        frm.set_df_property('current_performance', 'hidden', 1);

        if (frm.is_new()) {
            // Populate performance areas on new doc
            if (!frm.doc.current_performance || frm.doc.current_performance.length === 0) {
                PERFORMANCE_AREAS.forEach(area => {
                    let row = frappe.model.add_child(frm.doc, 'Current Performance Expectations', 'current_performance');
                    row.performance_area = area.performance_area;
                    row.criteria = area.criteria.join(' ');
                    row.rating = 'No Rating';
                });
                frm.refresh_field('current_performance');
            }

            // Fetch rating scale only once on new doc creation
            if (!frm.doc.table_rating_scale || frm.doc.table_rating_scale.length === 0) {
                load_rating_scale(frm);
            }
        }

        render_performance_html(frm);
        calculate_total(frm);
    }
});

frappe.ui.form.on('Current Performance Expectations', {
    rating: function(frm) {
        render_performance_html(frm);
        calculate_total(frm);
    }
});

function load_rating_scale(frm) {
    frappe.call({
        method: 'frappe.client.get',
        args: {
            doctype: 'Performance Appraisal Rating scale',
            name: 'Performance Appraisal Rating scale'
        },
        callback: function(response) {
            if (!response || !response.message) return;
            let bands = response.message.table_rating_scale;
            if (!bands || bands.length === 0) return;

            bands.forEach(function(band) {
                let row = frappe.model.add_child(frm.doc, 'Rating scale', 'table_rating_scale');
                row.score = band.score;
                row.description = band.description;
            });

            frm.refresh_field('table_rating_scale');
        }
    });
}

function calculate_total(frm) {
    let total = (frm.doc.current_performance || []).reduce(function(sum, row) {
        return sum + (RATING_SCORES[row.rating] || 0);
    }, 0);
    if (frm.doc.total != total) {
        frm.set_value('total', total);
    }
}

function render_performance_html(frm) {
    let rows_html = PERFORMANCE_AREAS.map(function(area, index) {
        let current_row = (frm.doc.current_performance || []).find(r => r.performance_area === area.performance_area);
        let current_rating = current_row ? current_row.rating : 'No Rating';

        let bullets = area.criteria.map(c =>
            `<div style="display:flex;align-items:flex-start;margin-bottom:4px;">
                <span style="color:#5e64ff;margin-right:6px;font-size:15px;line-height:1.4;">•</span>
                <span style="font-size:12px;color:#555;line-height:1.6;">${c}</span>
            </div>`
        ).join('');

        let options = RATING_OPTIONS.map(opt =>
            `<option value="${opt}" ${current_rating === opt ? 'selected' : ''}>${opt}</option>`
        ).join('');

        let bg = index % 2 === 0 ? '#ffffff' : '#fafbfc';

        return `
            <tr style="background:${bg};vertical-align:top;">
                <td style="padding:12px 15px;border:1px solid #d1d8dd;text-align:center;color:#888;font-size:12px;width:4%;">${index + 1}</td>
                <td style="padding:12px 15px;border:1px solid #d1d8dd;font-weight:600;font-size:13px;color:#2d3748;width:25%;">${area.performance_area}</td>
                <td style="padding:12px 15px;border:1px solid #d1d8dd;width:48%;">${bullets}</td>
                <td style="padding:12px 15px;border:1px solid #d1d8dd;width:23%;">
                    <select data-area="${area.performance_area}" style="width:100%;padding:7px 10px;border:1px solid #d1d8dd;border-radius:4px;font-size:12px;color:#333;background:#fff;cursor:pointer;">
                        ${options}
                    </select>
                </td>
            </tr>
        `;
    }).join('');

    let html = `
        <div style="padding:10px 0;">
            <table style="width:100%;border-collapse:collapse;">
                <thead>
                    <tr style="background:#f4f5f6;">
                        <th style="padding:12px 15px;border:1px solid #d1d8dd;font-size:12px;color:#6c757d;text-align:left;width:4%;">No.</th>
                        <th style="padding:12px 15px;border:1px solid #d1d8dd;font-size:12px;color:#6c757d;text-align:left;width:25%;">Performance Area</th>
                        <th style="padding:12px 15px;border:1px solid #d1d8dd;font-size:12px;color:#6c757d;text-align:left;width:48%;">Criteria</th>
                        <th style="padding:12px 15px;border:1px solid #d1d8dd;font-size:12px;color:#6c757d;text-align:left;width:23%;">Rating</th>
                    </tr>
                </thead>
                <tbody>${rows_html}</tbody>
            </table>
        </div>
    `;

    let $wrapper = frm.fields_dict['performance_html'].$wrapper;
    $wrapper.html(html);

    $wrapper.find('select').on('change', function() {
        let area = $(this).data('area');
        let val = $(this).val();
        let row = (frm.doc.current_performance || []).find(r => r.performance_area === area);
        if (row) {
            frappe.model.set_value(row.doctype, row.name, 'rating', val).then(() => {
                calculate_total(frm);
            });
        }
    });
}

