// ── Notify Supervisor
function notify_supervisor(frm) {
    if (frm.is_new()) {
        frappe.msgprint({
            title: __("Save Required"),
            message: __("Please save the document before sending a notification."),
            indicator: "orange",
        });
        return;
    }

    if (!frm.doc.employee) {
        frappe.msgprint({
            title: __("Missing Employee"),
            message: __("Please link an Employee before sending the notification."),
            indicator: "red",
        });
        return;
    }

    frappe.confirm(
        __(`Send an exit interview notification to the supervisor of <b>${frm.doc.full_name}</b>?`),
        () => {
            frappe.show_progress(__("Sending Notification"), 30, 100, __("Please wait..."));
            frappe.call({
                method: "corporate_services.api.notification.offboarding_schedule.offboarding_schedule.notify_supervisor_for_exit_interview",
                args: { docname: frm.doc.name },
                freeze: true,
                freeze_message: __("Sending notification to supervisor..."),
                callback(r) {
                    frappe.hide_progress();
                    if (!r.exc) {
                        frappe.show_alert({
                            message: __("Supervisor notified successfully."),
                            indicator: "green",
                        }, 5);
                        frm.reload_doc();
                    }
                },
                error() {
                    frappe.hide_progress();
                    frappe.msgprint({
                        title: __("Error"),
                        message: __("Failed to send notification. Please check the error log."),
                        indicator: "red",
                    });
                },
            });
        }
    );
}


// ── Send Offboarding Announcement
function send_offboarding_email(frm) {
    if (frm.is_new()) {
        frappe.msgprint({
            title: __("Save Required"),
            message: __("Please save the document before sending the announcement."),
            indicator: "orange",
        });
        return;
    }

    if (!frm.doc.employee) {
        frappe.msgprint({
            title: __("Missing Employee"),
            message: __("Please link an Employee before sending the announcement."),
            indicator: "red",
        });
        return;
    }

    // Open a dialog so the sender can review/edit before sending
    const dialog = new frappe.ui.Dialog({
        title: __("Send Offboarding Announcement"),
        size: "large",
        fields: [
            {
                fieldtype: "Check",
                fieldname: "send_to_all",
                label: __("Send to All Active Employees"),
                default: 0,
                onchange() {
                    const checked = dialog.get_value("send_to_all");
                    dialog.set_df_property("recipients", "reqd", checked ? 0 : 1);
                    dialog.set_df_property("recipients", "hidden", checked ? 1 : 0);
                    dialog.refresh();
                },
            },
            {
                fieldtype: "Data",
                fieldname: "recipients",
                label: __("Recipients (comma-separated emails)"),
                reqd: 1,
                description: __("e.g. team@company.com, hr@company.com"),
            },
            {
                fieldtype: "Data",
                fieldname: "signature_name",
                label: __("Sender Name (for signature)"),
                reqd: 1,
                default: frappe.session.user_fullname,
            },
            {
                fieldtype: "Section Break",
                label: __("Preview"),
            },
            {
                fieldtype: "HTML",
                fieldname: "email_preview",
                label: __("Email Preview"),
            },
        ],
        primary_action_label: __("Send"),
        primary_action(values) {
            // Validate: need recipients if not sending to all
            if (!values.send_to_all && !values.recipients) {
                frappe.msgprint({
                    title: __("Recipients Required"),
                    message: __("Please enter recipient emails or tick 'Send to All Active Employees'."),
                    indicator: "orange",
                });
                return;
            }

            const confirm_msg = values.send_to_all
                ? __("This will send the announcement to <b>all active employees</b>. Continue?")
                : __(`Send announcement to <b>${values.recipients}</b>?`);

            frappe.confirm(confirm_msg, () => {
                frappe.show_progress(__("Sending"), 30, 100, __("Please wait..."));
                frappe.call({
                    method: "corporate_services.api.notification.offboarding_schedule.offboarding_announcement.send_offboarding_announcement",
                    args: {
                        docname: frm.doc.name,
                        recipients: values.send_to_all ? "" : values.recipients,
                        send_to_all: values.send_to_all ? 1 : 0,
                        signature_name: values.signature_name,
                    },
                    freeze: true,
                    freeze_message: __("Sending offboarding announcement..."),
                    callback(r) {
                        frappe.hide_progress();
                        if (!r.exc) {
                            dialog.hide();
                            frappe.show_alert({
                                message: __(r.message || "Offboarding announcement sent successfully."),
                                indicator: "green",
                            }, 6);
                            frm.reload_doc();
                        }
                    },
                    error() {
                        frappe.hide_progress();
                        frappe.msgprint({
                            title: __("Error"),
                            message: __("Failed to send announcement. Please check the error log."),
                            indicator: "red",
                        });
                    },
                });
            });
        },
    });

    // Render a live preview inside the dialog once it's shown
    dialog.show();

    frappe.call({
        method: "corporate_services.api.notification.offboarding_schedule.offboarding_announcement.get_offboarding_email_preview",
        args: { docname: frm.doc.name },
        callback(r) {
            if (r.message) {
                const { subject, message } = r.message;
                dialog.fields_dict.email_preview.$wrapper.html(
                    `<div style="border:1px solid #e0e0e0; border-radius:4px; padding:16px; background:#fafafa;">
                        <p style="font-family:monospace; font-size:10pt; color:#555; margin:0 0 12px 0;">
                            <strong>Subject:</strong> ${subject}
                        </p>
                        <hr style="border:none; border-top:1px solid #e0e0e0; margin-bottom:12px;"/>
                        ${message}
                    </div>`
                );
            }
        },
    });
}

frappe.ui.form.on('Staff Requisition', {

	refresh(frm) {

		// ── 1. Dashboard connections ─────────────────────────────
		frm.dashboard.add_transactions([{
			label: 'Recruitment',
			items: ['Job Opening']
		}]);

		if (frm.is_new()) return;

		// ── 2. Create Job Posting button ─────────────────────────
		if (
			frm.doc.status === 'APPROVED FOR RECRUITMENT' &&
			frappe.user.has_role('HR Manager')
		) {
			frm.add_custom_button('Create Job Posting', function () {
				frappe.new_doc('Job Opening', {
					custom_staff_requisition : frm.doc.name,
					job_title                : frm.doc.title,
					department               : frm.doc.department,
					designation              : frm.doc.designation,
				});
			}, 'Create');
		}
	},

	// ── 3. before_workflow_action ────────────────────────────────
	// This hook fires BEFORE Frappe processes any workflow button click.
	// We MUST return Promise.resolve() so the form stays interactive.
	// For "Needs Clarification" we cancel the default transition here,
	// show our dialog, send the email, then manually save + set the
	// workflow state ourselves - no apply_workflow, no execute_workflow_action.
	before_workflow_action(frm) {
		const action = frm.selected_workflow_action;

		if (action !== 'Needs Clarification') {
			// All other workflow actions pass through untouched
			return Promise.resolve();
		}

		// ── Show dialog AFTER resolving so form stays interactive ──
		// We resolve immediately to unblock Frappe, then open our
		// dialog. We prevent the default transition by overriding
		// after_workflow_action instead.
		frm._handle_clarification = true;
		return Promise.resolve();
	},

	// ── 4. after_workflow_action ─────────────────────────────────
	// Frappe calls this right after applying the workflow transition.
	// We undo the auto-transition and show our dialog instead.
	after_workflow_action(frm) {
		if (!frm._handle_clarification) return;
		frm._handle_clarification = false;

		// Frappe already changed the workflow state - reload the
		// doc back to its previous state, then show the dialog
		// so the user can provide the message before it sticks.
		show_clarification_dialog(frm);
	}
});


function show_clarification_dialog(frm) {

	const d = new frappe.ui.Dialog({
		title  : 'Needs Clarification',
		fields : [{
			label      : 'Clarification Message',
			fieldname  : 'message',
			fieldtype  : 'Small Text',
			reqd       : 1,
			description: 'This message will be emailed to the requestor.'
		}],
		primary_action_label: 'Send',
		primary_action(values) {

			const btn = d.get_primary_btn();
			btn.prop('disabled', true).text('Sending…');

			frappe.call({
				method: 'corporate_services.api.staff_requisition.staff_requisition.send_clarification_email',
				args  : {
					docname: frm.doc.name,
					message: values.message
				},
				callback(r) {
					if (r.exc) {
						btn.prop('disabled', false).text('Send');
						frappe.msgprint({
							title    : 'Email Error',
							message  : 'Failed to send clarification email.',
							indicator: 'red'
						});
						return;
					}

					d.hide();
					frappe.show_alert({
						message  : 'Clarification request sent successfully.',
						indicator: 'green'
					}, 4);
					frm.reload_doc();
				},
				error() {
					btn.prop('disabled', false).text('Send');
					frappe.msgprint({
						title    : 'Server Error',
						message  : 'Could not reach the server. Please try again.',
						indicator: 'red'
					});
				}
			});
		}
	});

	d.show();
	setTimeout(() => {
		const f = d.get_field('message');
		if (f && f.$input) f.$input.focus();
	}, 200);
}
